            }

            return formatAsJson(title, description);

        } catch (Exception e) {
            return formatAsJson("Error", "An exception occurred while fetching the preview: " + e.getMessage());
        }
    }

    private String extractTitle(String html) {
        Pattern pattern = Pattern.compile("<title[^>]*>(.*?)</title>", Pattern.CASE_INSENSITIVE | Pattern.DOTALL);
        Matcher matcher = pattern.matcher(html);
        if (matcher.find()) {
